mapper.select:
SELECT r.id, r.date_time as createtime, r.consumable_id, r.quantity, r.remark, r.type, r.operator, r.applicant, c.type as consumableType, c.location as consumableLocation FROM bus_consumable_record r LEFT JOIN bus_consumable c ON r.consumable_id = c.id
AND r.type = #{record.type}
AND c.type LIKE CONCAT('%', CONCAT(#{record.consumableType}, '%'))
AND (r.type LIKE '%入库%' OR r.type = 'IN')
AND (r.type LIKE '%出库%' OR r.type = 'OUT')
AND r.date_time >= #{startTime}
AND r.date_time <= #{endTime}
ORDER BY r.date_time DESC
